function useQuotes() {
  const { actor, isFetching } = useActor(createActor);
  return useQuery({
    queryKey: ["quotes"],
    queryFn: async () => {
      if (!actor) return [];
      return (await actor.getQuotes()).filter((q) => q.active);
    },
    enabled: !!actor && !isFetching,
    staleTime: 3e5
  });
}
